  ('fire-eq-tech-moex-02170', 'fire-eq-tech', 'fire-eq-tech-moex-102-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '根據消防安全設備檢修專業機構管理辦法之規定，合格證書之有效期限為A年，期限屆滿前B個月，得 檢附下列文件向內政部申請延展，每次延展期限為C年。則A，B，C各值為何？', '["A=1，B=3，C=1", "A=1，B=1，C=1", "A=3，B=3，C=1", "A=3，B=3，C=3"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "0a34ee03f2ae", "answer_pdf_sha1": "d13e51cedf0e", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0708", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
